import{_ as a,o as c,c as r,a2 as d}from"./chunks/framework.BKG_UbFK.js";const p=JSON.parse('{"title":"Безопасность","description":"","frontmatter":{},"headers":[],"relativePath":"ru/guide/security.md","filePath":"ru/guide/security.md"}'),o={name:"ru/guide/security.md"};function t(l,e,i,s,n,u){return c(),r("div",null,[...e[0]||(e[0]=[d('<h1 id="безопасность" tabindex="-1">Безопасность <a class="header-anchor" href="#безопасность" aria-label="Permalink to &quot;Безопасность&quot;">​</a></h1><p>Clearance прошёл выделенный аудит безопасности перед публикацией, а также два дополнительных этапа усиления защиты перед релизом. Основные моменты: ограничения (ceiling) против повышения привилегий на каждом пути выдачи разрешений (как при прямой выдаче, так и при синхронизации на уровне роли), приоритет запрета в контекстных переопределениях, санитайзер SVG на основе allow-list, защищённое пространство имён разрешений <code>clearance-*</code> и безопасные для гостя директивы Blade.</p><h2 id="доступ-к-панели-и-точечные-права-на-запись" tabindex="-1">Доступ к панели и точечные права на запись <a class="header-anchor" href="#доступ-к-панели-и-точечные-права-на-запись" aria-label="Permalink to &quot;Доступ к панели и точечные права на запись&quot;">​</a></h2><p>Доступ на чтение ко всей панели требует разрешения <code>clearance-access</code> (проверяется через <code>can()</code>, никогда через <code>hasRole()</code>). Операции записи в каждом разделе защищены отдельным делегируемым разрешением - все они создаются <code>clearance:install</code> и назначаются <code>super_admin</code>:</p><table tabindex="0"><thead><tr><th>Разрешение</th><th>Контролирует</th></tr></thead><tbody><tr><td><code>clearance-permissions-write</code></td><td>Создание / редактирование / удаление разрешений</td></tr><tr><td><code>clearance-roles-write</code></td><td>Создание / редактирование / удаление ролей и их назначений разрешений</td></tr><tr><td><code>clearance-guards-write</code></td><td>Создание / редактирование / удаление guard&#39;ов</td></tr><tr><td><code>clearance-settings-write</code></td><td>Редактирование метаданных отображения, иконок, цветов, роли по умолчанию</td></tr><tr><td><code>clearance-users-write</code></td><td>Назначение / удаление ролей для конкретного пользователя</td></tr></tbody></table><p>Если строка точечного разрешения вообще не существует в базе данных (устаревшее состояние до появления seed&#39;а), проверка откатывается к <code>clearance-access</code> для обратной совместимости.</p><h2 id="защищенное-пространство-имен-clearance" tabindex="-1">Защищённое пространство имён <code>clearance-*</code> <a class="header-anchor" href="#защищенное-пространство-имен-clearance" aria-label="Permalink to &quot;Защищённое пространство имён `clearance-*`&quot;">​</a></h2><p>Разрешения <code>clearance-*</code> зарезервированы: их нельзя создавать, переименовывать, удалять или добавлять к какой-либо роли иначе как через собственный процесс установки пакета - даже актором <code>super_admin</code> для самой роли <code>super_admin</code>.</p><h2 id="ограничения-против-повышения-привилегии" tabindex="-1">Ограничения против повышения привилегий <a class="header-anchor" href="#ограничения-против-повышения-привилегии" aria-label="Permalink to &quot;Ограничения против повышения привилегий&quot;">​</a></h2><p>Каждый путь выдачи разрешений в Clearance применяет ceiling, так что актор никогда не может выдать больше, чем имеет сам:</p><ul><li><strong>Ceiling-роли</strong> - роль может объявить родительскую роль, чьё множество разрешений выступает верхней границей. Любое избыточное разрешение автоматически и незаметно обрезается при <code>RoleService::setParent()</code> и при каждой последующей синхронизации разрешений - без исключения, без сообщения об ошибке. Удаление разрешений у родителя автоматически каскадно распространяется на каждую дочернюю роль. См. <a href="/clearance-docs/ru/features/roles.html">Роли</a> для полного API ceiling.</li><li><strong>Модуль пользователей</strong> - и назначение ролей, и прямая/переопределяющая выдача разрешений применяют ограничение по привилегиям: актор, не являющийся <code>super_admin</code>, не может изменять собственные назначения и не может выдать разрешение, которым не обладает сам. См. <a href="/clearance-docs/ru/features/users.html">Пользователи</a>.</li></ul><h2 id="приоритет-запрета-в-контекстных-переопределениях" tabindex="-1">Приоритет запрета в контекстных переопределениях <a class="header-anchor" href="#приоритет-запрета-в-контекстных-переопределениях" aria-label="Permalink to &quot;Приоритет запрета в контекстных переопределениях&quot;">​</a></h2><p>Переопределения разрешений по контексту (<code>clr_ctx_overrides</code>) поддерживают <code>forced_on</code> и <code>forced_off</code>. <code>forced_off</code> всегда побеждает - даже над разрешением, выданным глобальной ролью. Не существует пути, позволяющего выдаче с более низким приоритетом перекрыть явный запрет. См. <a href="/clearance-docs/ru/guide/architecture.html#how-resolution-works">Архитектуру</a> для полного порядка разрешения (resolution).</p><h2 id="санитизация-svg" tabindex="-1">Санитизация SVG <a class="header-anchor" href="#санитизация-svg" aria-label="Permalink to &quot;Санитизация SVG&quot;">​</a></h2><p>Каждая предоставленная пользователем иконка (метаданные отображения роли/guard&#39;а в панели Настроек) проходит через санитайзер на основе allow-list как перед сохранением, так и при рендеринге - а не единоразовую проверку при загрузке.</p><h2 id="безопасные-для-гостя-директивы-blade" tabindex="-1">Безопасные для гостя директивы Blade <a class="header-anchor" href="#безопасные-для-гостя-директивы-blade" aria-label="Permalink to &quot;Безопасные для гостя директивы Blade&quot;">​</a></h2><p><code>@canin</code> и <code>@hasrolein</code> обе безопасно разрешаются (возвращают <code>false</code>) для гостевого пользователя - они никогда не выбрасывают исключение.</p><h2 id="обход-gate-деиствует-во-всем-приложении" tabindex="-1">Обход Gate действует во всём приложении <a class="header-anchor" href="#обход-gate-деиствует-во-всем-приложении" aria-label="Permalink to &quot;Обход Gate действует во всём приложении&quot;">​</a></h2><p><code>super_admin_gate_bypass</code> (по умолчанию <code>false</code>) управляет тем, обходит ли роль <code>super_admin</code> все проверки <code>can()</code> / <code>Gate::allows()</code> / политик Laravel глобально, через хук <code>Gate::before()</code>.</p><div class="warning custom-block"><p class="custom-block-title">Не ограничено рамками панели</p><p>Если включено, любой пользователь, обладающий <code>super_admin</code>, пропускает все проверки Gate во всём приложении - не только проверки панели Clearance. Включайте это осознанно. См. <a href="/clearance-docs/ru/features/super-admin.html">Super Admin</a> для поведения обнаружения алиасов и повышения роли.</p></div><h2 id="нюансы-важные-для-безопасности" tabindex="-1">Нюансы, важные для безопасности <a class="header-anchor" href="#нюансы-важные-для-безопасности" aria-label="Permalink to &quot;Нюансы, важные для безопасности&quot;">​</a></h2><ul><li><code>forced_off</code> всегда побеждает - даже над разрешением, выданным глобальной ролью.</li><li>Ceiling-роль только обрезает, но никогда не выдаёт - установка разрешительного родителя сама по себе не даёт дочерней роли ничего.</li><li>Обход Gate (<code>super_admin_gate_bypass</code>) действует во всём приложении, а не только в рамках панели.</li><li>Модуль пользователей по умолчанию выключен (<code>modules.users = false</code>).</li><li>Разрешения <code>clearance-*</code> неприкосновенны вне процесса установки, даже для <code>super_admin</code>.</li><li>Всегда запускайте <code>clearance:install</code>, а не обычный <code>migrate</code>, на новой установке - см. <a href="/clearance-docs/ru/guide/installation.html">Установку</a>.</li></ul><h2 id="смотрите-также" tabindex="-1">Смотрите также <a class="header-anchor" href="#смотрите-также" aria-label="Permalink to &quot;Смотрите также&quot;">​</a></h2><ul><li><a href="/clearance-docs/ru/guide/architecture.html">Архитектура</a> - порядок разрешения (resolution) и схема <code>clr_*</code></li><li><a href="/clearance-docs/ru/features/roles.html">Роли</a> - ceiling-роли подробно</li><li><a href="/clearance-docs/ru/features/users.html">Пользователи</a> - ограничение по привилегиям при назначении ролей/разрешений</li><li><a href="/clearance-docs/ru/features/super-admin.html">Super Admin</a> - обход Gate и обнаружение алиасов</li></ul>',24)])])}const f=a(o,[["render",t]]);export{p as __pageData,f as default};
